package arch.day71;
import java.util.*;

public class Day71Advanced {
    static record Review(String topic, int confidence, boolean needsRevision) {}

    public static void main(String[] args) {
        List<Review> reviews = List.of(
            new Review("Redis - Caching & Advanced Patterns", 72, true),
            new Review("Coding Practice", 81, false),
            new Review("Interview Explanation", 68, true)
        );

        long reviseCount = reviews.stream().filter(Review::needsRevision).count();
        int avg = (int) reviews.stream().mapToInt(Review::confidence).average().orElse(0);

        System.out.println("avgConfidence = " + avg);
        System.out.println("needsRevision = " + reviseCount);
    }
}
